#nullable enable // autogenerated  

using MVZ2.GameContent.Projectiles;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.smallDispenser)]
    public class SmallDispenser : DispenserFamily
    {
        public SmallDispenser(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            InitShootTimer(entity);
            SetTriggerCount(entity, 0);
            SetTriggerCooldownTimer(entity, new FrameTimer(0));
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);

            // 更新触发冷却计时器 
            var cooldownTimer = GetTriggerCooldownTimer(entity);
            if (cooldownTimer != null)
            {
                cooldownTimer.Run(entity.GetAttackSpeed());
            }

            if (!entity.IsEvoked())
            {
                ShootTick(entity);
                return;
            }
        }

        public override bool CanTrigger(Entity entity)
        {
            // 检查基础触发条件
            if (!base.CanTrigger(entity))
                return false;

            // 检查是否在冷却中  
            var cooldownTimer = GetTriggerCooldownTimer(entity);
            if (cooldownTimer != null && !cooldownTimer.Expired)
                return false;

            return true;
        }

        public override Entity? Shoot(Entity entity)
        {
            var triggerCount = GetTriggerCount(entity);
            NamespaceID projectileID;
            float damageMultiplier = 1f;

            if (triggerCount == 0)
            {
                // 未触发：正常发射雪球  
                projectileID = VanillaProjectileID.snowball;
                damageMultiplier = 1f;
            }
            else if (triggerCount == 1)
            {
                // 触发1次：50%木球，50%雪球  
                if (entity.RNG.Next(2) == 0)
                {
                    projectileID = VanillaProjectileID.woodenBall;
                    damageMultiplier = 1f;
                }
                else
                {
                    projectileID = VanillaProjectileID.snowball;
                    damageMultiplier = 1f;
                }
            }
            else
            {
                // 触发2次及以上：50%木球，25%巨石，5%石子，20%雪球  
                int rand = entity.RNG.Next(100);
                if (rand < 50)
                {
                    projectileID = VanillaProjectileID.woodenBall;
                    damageMultiplier = 1f;
                }
                else if (rand < 75)
                {
                    projectileID = VanillaProjectileID.boulder;
                    damageMultiplier = 2f;
                }
                else if (rand < 80)
                {
                    projectileID = VanillaProjectileID.cobble;
                    damageMultiplier = 0.5f;
                }
                else
                {
                    projectileID = VanillaProjectileID.snowball;
                    damageMultiplier = 1f;
                }
            }

            var param = entity.GetShootParams();
            param.projectileID = projectileID;
            param.damage = entity.GetDamage() * damageMultiplier;
            var projectile = entity.ShootProjectile(param);

            if (projectile != null)
            {
                projectile.Timeout = Mathf.CeilToInt(entity.GetRange() / entity.GetShotVelocity().magnitude);
            }
            return projectile;
        }

        protected override void OnTrigger(Entity entity)
        {
            base.OnTrigger(entity);
            var triggerCount = GetTriggerCount(entity);

            if (triggerCount < 2)
            {
                // 前2次触发：增加计数  
                SetTriggerCount(entity, triggerCount + 1);
            }
            else
            {
                // 第3次及以后触发：发射巨石并进入冷却  
                var velocity = Vector3.right * 3;
                if (entity.IsFacingLeft())
                {
                    velocity.x *= -1;
                }

                var param = entity.GetShootParams();
                param.projectileID = VanillaProjectileID.boulder;
                param.damage = entity.GetDamage() * 3f;
                param.velocity = velocity;
                entity.ShootProjectile(param);
                entity.PlaySound(VanillaSoundID.odd);

                // 重置冷却计时器  
                var cooldownTimer = GetTriggerCooldownTimer(entity);
                if (cooldownTimer != null)
                {
                    cooldownTimer.ResetTime(TRIGGER_COOLDOWN);
                }
            }
        }

        protected override void OnEvoke(Entity entity)
        {
            base.OnEvoke(entity);
            var velocity = Vector3.right * 3;
            velocity.x *= entity.GetFacingX();

            var shootParams = entity.GetShootParams();
            shootParams.projectileID = VanillaProjectileID.largeSnowball;
            shootParams.velocity = velocity;
            entity.ShootProjectile(shootParams);
            entity.PlaySound(VanillaSoundID.odd);
        }

        private static readonly NamespaceID ID = VanillaContraptionID.smallDispenser;
        private static readonly VanillaEntityPropertyMeta<int> PROP_TRIGGER_COUNT = new VanillaEntityPropertyMeta<int>("TriggerCount");
        private static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_TRIGGER_COOLDOWN_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("TriggerCooldownTimer");

        private static int GetTriggerCount(Entity entity) => entity.GetBehaviourField<int>(ID, PROP_TRIGGER_COUNT);
        private static void SetTriggerCount(Entity entity, int value) => entity.SetBehaviourField(ID, PROP_TRIGGER_COUNT, value);
        private static FrameTimer? GetTriggerCooldownTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(ID, PROP_TRIGGER_COOLDOWN_TIMER);
        private static void SetTriggerCooldownTimer(Entity entity, FrameTimer timer) => entity.SetBehaviourField(ID, PROP_TRIGGER_COOLDOWN_TIMER, timer);

        public const int TRIGGER_COOLDOWN = 150;
    }
}